const items = $input.all();
const emails = [];

for (const item of items) {
  const msg = item.json;
  let body = '';
  try {
    const payload = msg.payload || {};
    if (payload.body && payload.body.data) {
      body = Buffer.from(payload.body.data, 'base64').toString('utf-8');
    } else if (payload.parts) {
      for (const part of (payload.parts || [])) {
        if (part.mimeType === 'text/plain' && part.body && part.body.data) {
          body = Buffer.from(part.body.data, 'base64').toString('utf-8'); break;
        }
        for (const sub of (part.parts || [])) {
          if (sub.mimeType === 'text/plain' && sub.body && sub.body.data) {
            body = Buffer.from(sub.body.data, 'base64').toString('utf-8'); break;
          }
        }
      }
    }
    if (!body && msg.snippet) body = msg.snippet;
  } catch(e) {}

  const headers = (msg.payload && msg.payload.headers) || [];
  const subject = (headers.find(h => h.name && h.name.toLowerCase() === 'subject') || {}).value || msg.snippet || '';
  const searchText = (body + ' ' + subject).toLowerCase();

  // Skip anything Shopify-related
  if (searchText.includes('shopify')) continue;
  if (searchText.includes('shop_')) continue;
  if (searchText.includes('payout')) continue; // Shopify payouts

  // Extract amount and currency
  let amount = null, currency = null;
  const patterns = [
    /([A-Z]{3})s*[$]?s*([d,]+.?d*)/,
    /([d,]+.?d*)s*(USD|SGD|HKD|AUD|EUR|GBP)/
  ];
  for (const pat of patterns) {
    const m = (body + ' ' + subject).match(pat);
    if (!m) continue;
    if (/^[A-Z]{3}$/.test(m[1])) { currency = m[1]; amount = parseFloat(m[2].replace(/,/g,'')); }
    else { amount = parseFloat(m[1].replace(/,/g,'')); currency = m[2]; }
    if (amount && currency) break;
  }

  if (!amount || !currency) continue; // can't parse — skip silently

  // Skip non-round amounts — client invoices are always whole numbers
  // Round = no cents, or exactly .00
  const isRound = amount % 1 === 0;
  if (!isRound) continue; // Shopify payouts are always irregular (e.g. $588.93)

  // Extract invoice number if present
  const invMatch = (body + ' ' + subject).match(/INV-[wd-]+/i);
  const invoiceNumber = invMatch ? invMatch[0].toUpperCase() : null;

  emails.push({
    emailId: msg.id,
    subject,
    amount,
    currency,
    invoiceNumber,
    date: new Date().toISOString().split('T')[0]
  });
}

return [{ json: { emails, count: emails.length } }];

const parsedData = $('Parse All Emails').first().json;
const emails = parsedData.emails || [];
const today = new Date().toISOString().split('T')[0];

if (emails.length === 0) {
  return [{ json: { matched: false, noAction: true, date: today } }];
}

const allRows = $input.all();
const openRows = allRows.filter(r => {
  const s = (r.json['Status'] || '').toString().trim();
  return !['Payment Complete', 'Collections'].includes(s) && r.json['Invoice #'];
});

const results = [];

for (const email of emails) {
  let match = null, confidence = 'none';

  // Priority 1: invoice number match
  if (email.invoiceNumber) {
    const found = openRows.find(r =>
      (r.json['Invoice #'] || '').toString().trim().toUpperCase() === email.invoiceNumber
    );
    if (found) { match = found; confidence = 'high'; }
  }

  // Priority 2: exact amount + currency match (only if single open invoice at that amount)
  if (!match && email.amount) {
    const hits = openRows.filter(r => {
      const amt = parseFloat((r.json['Amount'] || '0').toString().replace(/,/g,''));
      const cur = (r.json['Currency'] || '').toString().trim().toUpperCase();
      return Math.abs(amt - email.amount) < 0.01 && cur === email.currency;
    });
    if (hits.length === 1) { match = hits[0]; confidence = 'medium'; }
    // If ambiguous (multiple matches) or no match — skip silently, no Slack noise
  }

  if (match) {
    results.push({
      matched: true,
      confidence,
      clientName: match.json['Client Name'] || '',
      invoiceNumber: match.json['Invoice #'] || '',
      airwallexInvoiceId: match.json['Airwallex Invoice ID'] || '',
      amount: email.amount,
      currency: email.currency,
      paymentDate: today
    });
  }
  // No match → silently dropped. Not Slack noise.
}

// If nothing matched after processing real client emails, still return noAction
if (results.length === 0) {
  return [{ json: { matched: false, noAction: true, date: today } }];
}

return results.map(r => ({ json: r }));
